<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    denominator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1240</span></span>
